  '175_15': { example2: "Environmental consultants advise on the ecological impact of large infrastructure projects.", example2Kr: "환경 컨설턴트들이 대규모 인프라 프로젝트의 생태적 영향에 대해 조언한다." },
  '175_16': { example2: "Career promotion in ecology often reflects a scientist's impact on conservation policy.",   example2Kr: "생태학에서의 경력 승진은 종종 과학자의 보전 정책에 대한 영향을 반영한다." },
  '175_17': { example2: "International collaboration among wildlife NGOs has strengthened global anti-poaching efforts.", example2Kr: "야생 동물 NGO들 사이의 국제 협력이 전 세계 밀렵 방지 노력을 강화했다." },
  '175_18': { example2: "An apprenticeship in organic farming teaches soil management and sustainable crop rotation.", example2Kr: "유기농 농업의 수습 과정이 토양 관리와 지속 가능한 윤작을 가르친다." },
