  // Day 176
  '176_0':  { example2: "Community fire rituals practiced for centuries now inform modern controlled burn strategies.", example2Kr: "수 세기 동안 행해진 공동체 불 의식이 이제 현대적인 통제된 소각 전략에 정보를 제공한다." },
  '176_1':  { example2: "Sacred groves attached to temples have protected biodiversity for over two millennia.",      example2Kr: "사원에 딸린 신성한 숲이 2000년 이상 생물 다양성을 보호해왔다." },
  '176_2':  { example2: "The doctrine of environmental care has been formally adopted by several major religions.",   example2Kr: "환경 보호 교리가 여러 주요 종교에 의해 공식적으로 채택되었다." },
  '176_3':  { example2: "Faith-based NGOs and local clergy have united to combat illegal deforestation in the region.", example2Kr: "신앙 기반 NGO와 지역 성직자들이 지역의 불법 삼림 벌채에 맞서기 위해 단결했다." },
  '176_4':  { example2: "Ancient scripture passages on land and water stewardship inspire modern conservation ethics.", example2Kr: "토지와 수자원 관리에 관한 고대 경전 구절이 현대 보전 윤리에 영감을 준다." },
  '176_5':  { example2: "Both secular science bodies and faith institutions agree that climate change is urgent.",     example2Kr: "세속적 과학 기관과 신앙 기관 모두 기후 변화가 긴급하다는 데 동의한다." },
  '176_6':  { example2: "A Shinto shrine forest in Japan has preserved rare old-growth trees for over 1,000 years.",  example2Kr: "일본의 신도 신사 숲이 1000년 이상 희귀한 원시림 나무들을 보존해왔다." },
  '176_7':  { example2: "Devout communities have cleared tons of plastic waste from sacred river banks each year.",    example2Kr: "독실한 공동체가 매년 신성한 강둑에서 수 톤의 플라스틱 폐기물을 청소했다." },
  '176_8':  { example2: "Challenging scientific orthodoxy has led to new understandings of ecosystem collapse speed.", example2Kr: "과학적 정통 이론에 도전하는 것이 생태계 붕괴 속도에 대한 새로운 이해로 이어졌다." },
  '176_9':  { example2: "Framing sustainability as economic heresy has delayed critical policy change for decades.",   example2Kr: "지속 가능성을 경제적 이단으로 규정하는 것이 수십 년 동안 중요한 정책 변화를 지연시켰다." },
  '176_10': { example2: "Neo-pagan traditions are increasingly focusing their rituals on environmental healing.",       example2Kr: "신이교 전통이 점점 환경 치유에 의식의 초점을 맞추고 있다." },
  '176_11': { example2: "The myth that technological growth alone can solve ecological crises is losing credibility.",  example2Kr: "기술 성장만으로 생태 위기를 해결할 수 있다는 신화가 신뢰성을 잃고 있다." },
  '176_12': { example2: "Regional folklore often encodes detailed ecological knowledge about local seasonal changes.",  example2Kr: "지역 민간 전승은 종종 지역 계절 변화에 대한 상세한 생태 지식을 담고 있다." },
  '176_13': { example2: "Ancient fishing taboos in Pacific island communities protected reefs for many generations.",   example2Kr: "태평양 섬 공동체의 고대 낚시 금기가 여러 세대에 걸쳐 산호초를 보호했다." },
  '176_14': { example2: "A harvest rite marking seasons embeds respect for nature's cycles into community culture.",   example2Kr: "계절을 기념하는 수확 의식이 자연의 순환에 대한 존중을 공동체 문화에 새긴다." },
  '176_15': { example2: "Reclaiming ancestral land rights has been vital to indigenous-led conservation programs.",    example2Kr: "조상 토지권 회복이 토착민 주도 보전 프로그램에 필수적이었다." },
  '176_16': { example2: "The orca is a totem for Northwest Coast peoples, guiding conservation of its habitat.",       example2Kr: "범고래는 북서 해안 민족들의 토템으로, 서식지 보전을 안내한다." },
  '176_17': { example2: "Eco-theology courses are growing in seminaries seeking to prepare green faith leaders.",      example2Kr: "친환경 신앙 지도자를 준비하려는 신학교에서 생태 신학 과정이 성장하고 있다." },
  '176_18': { example2: "Museum exhibits of forest relics highlight what old-growth ecosystems once looked like.",     example2Kr: "산림 유물의 박물관 전시가 원시림 생태계가 한때 어떻게 보였는지를 강조한다." },
  '176_19': { example2: "A sense of reverence for biodiversity is growing among urban youth worldwide.",               example2Kr: "생물 다양성에 대한 경외심이 전 세계 도시 청년들 사이에서 성장하고 있다." },

  // Day 177
  '177_0':  { example2: "Rugged coastal terrain has protected some of the last temperate old-growth forests.",        example2Kr: "험준한 해안 지형이 마지막 온대 원시림 중 일부를 보호했다." },
  '177_1':  { example2: "Healthy upstream forest cover is the most cost-effective watershed protection strategy.",    example2Kr: "건강한 상류 산림 피복이 가장 비용 효과적인 유역 보호 전략이다." },
  '177_2':  { example2: "Flash floods carved new canyons in the landscape following the record storm event.",         example2Kr: "기록적인 폭풍 사건 이후 돌발 홍수가 지형에 새로운 협곡을 깎았다." },
  '177_3':  { example2: "The peninsula's unique isolation enabled endemic species found nowhere else on Earth.",       example2Kr: "반도의 독특한 고립이 지구 어디에도 없는 토착 종의 출현을 가능하게 했다." },
